mapper.select:
SELECT d.*
FROM iot_device d

    d.del_flag = 0

        AND d.device_name LIKE CONCAT('%',#{deviceName},'%')


        AND d.device_type = #{deviceType}


        AND d.status = #{status}


        AND d.product_id = #{productId}


        AND d.create_time >= #{startTime}


        AND d.create_time <= #{endTime}




        AND EXISTS (
            SELECT 1
            FROM iot_device_auth a
            WHERE a.device_id = d.id
              AND a.del_flag = 0
              AND a.status = 1
              AND (a.effective_time IS NULL OR a.effective_time <= NOW())
              AND (a.expire_time IS NULL OR a.expire_time >= NOW())

                  AND a.tenant_id = #{currentTenantId}

        )


ORDER BY d.create_time DESC
